// Inputs: msg.payload may be the dlq dict itself (from filter/parse/poll/
// archive paths) OR may be a wrapper with `payload`. Normalise.
let src = msg.payload;
if (src && typeof src === 'object' && src.payload && src.payload.error_type) {
    src = src.payload;
}
if (!src || typeof src !== 'object') {
    src = { error_type: 'uncaught', error_message: String(msg.payload || msg.error || 'unknown') };
}
const dlq = {
    error_type: src.error_type || 'uncaught',
    error_message: src.error_message || 'unknown',
    error_timestamp: src.error_timestamp || new Date().toISOString(),
    filename: src.filename || null,
    source_topic: src.source_topic || null,
    original_envelope: src.original_envelope || null
};

const m = global.get('metrics') || {};
m.facis_sftp_dlq_total = m.facis_sftp_dlq_total || {};
m.facis_sftp_dlq_total[dlq.error_type] = (m.facis_sftp_dlq_total[dlq.error_type] || 0) + 1;
global.set('metrics', m);

return {
    topic: env.get('INGEST_DLQ_TOPIC') || 'sftp.ingest.dlq',
    key: dlq.filename || 'unknown',
    payload: JSON.stringify(dlq)
};
